package main

import (
	"fmt"
	"os"
)

func main() {
	input := ""
	m := make(map[rune]int)
	marker := ""

	for pos, char := range input {
		m[char]++
		marker += string(char)

		if m[char] > 1 { // If the letter already ocurred more then once.
			m = make(map[rune]int) // clear map by re-creating
			fmt.Println()
			fmt.Print(marker)
			for i, letter := range marker {
				if letter == char {
					marker = marker[i+1:]
					m = make(map[rune]int)
					for _, newLetter := range marker {
						m[newLetter]++
					}
					fmt.Print("#" + string(marker))
					break
				}
			}
		} else if len(marker) == 14 {
			fmt.Println()
			fmt.Println(fmt.Sprint(pos+1) + "::" + marker)
			os.Exit(3)
		}
	}
}
